export class Camera {
    #pos;
    constructor() {
        this.#pos = { x: 0, y: 0 };
    }
    set x(value) {
        this.#pos.x = value;
    }
    set y(value) {
        this.#pos.y = value;
    }
    get x() {
        return this.#pos.x;
    }
    get y() {
        return this.#pos.y;
    }
    getPos() {
        return Object.assign({}, this.#pos);
    }
    getViewOffset() {
        let offsetX = -this.#pos.x;
        let offsetY = -this.#pos.y;
        return { x: offsetX, y: offsetY };
    }
}
